class InAppPurchaseGateway(
    private val appContext: Context
) : PaymentGateway {
    override suspend fun process(request: PaymentRequest): PaymentResult = withContext(Dispatchers.IO) {
        if (request.methodType != PaymentMethodType.IN_APP_PURCHASE) {
            return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Invalid payment method")
        }
        if (request.productId.isNullOrBlank()) {
            return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Missing productId")
        }
        if (!supportsPlayBilling(appContext)) {
            return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Billing unsupported on this device")
        }
        val transactionId = "iap_${UUID.randomUUID()}"
        PaymentResult(
            requestId = request.id,
            status = PaymentStatus.SUCCESS,
            transactionId = transactionId,
            message = "Purchase completed"
        )
    }

    override suspend fun verifyTransaction(transactionId: String): Boolean = withContext(Dispatchers.IO) {
        transactionId.isNotBlank()
    }

    private fun supportsPlayBilling(context: Context): Boolean {
        return context.packageManager.hasSystemFeature(PackageManager.FEATURE_TOUCHSCREEN) ||
            Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP
    }
}

class WalletTransactionGateway(
    private val secureStorage: SecureStorage
) : PaymentGateway {
    override suspend fun process(request: PaymentRequest): PaymentResult = withContext(Dispatchers.IO) {
        if (request.methodType != PaymentMethodType.WALLET) {
            return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Invalid payment method")
        }
        if (request.walletAccountId.isNullOrBlank()) {
            return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Missing walletAccountId")
        }
        val token = secureStorage.getString("wallet_token_${request.walletAccountId}")
            ?: return@withContext PaymentResult(request.id, PaymentStatus.FAILED, message = "Wallet not authorized")

        val masked = token.takeLast(4)
        val transactionId = "wallet_${UUID.randomUUID()}_$masked"
        PaymentResult(
            requestId = request.id,
            status = PaymentStatus.SUCCESS,
            transactionId = transactionId,
            message = "Wallet transaction completed"
        )
    }

    override suspend fun verifyTransaction(transactionId: String): Boolean = withContext(Dispatchers.IO) {
        transactionId.startsWith("wallet_") || transactionId.startsWith("iap_")
    }

    fun authorizeWallet(walletAccountId: String, authToken: String) {
        secureStorage.putString("wallet_token_$walletAccountId", authToken)
    }

    fun revokeWallet(walletAccountId: String) {
        secureStorage.remove("wallet_token_$walletAccountId")
    }
}

class PaymentManager(
    private val context: Context,
    private val inAppGateway: InAppPurchaseGateway = InAppPurchaseGateway(context),
    private val walletGateway: WalletTransactionGateway = WalletTransactionGateway(InMemorySecureStorage()),
    private val ioDispatcher: CoroutineDispatcher = Dispatchers.IO
) {
    private val listeners = mutableSetOf<PaymentListener>()

    fun addListener(listener: PaymentListener) {
        listeners.add(listener)
    }

    fun removeListener(listener: PaymentListener) {
        listeners.remove(listener)
    }

    suspend fun processPayment(request: PaymentRequest): PaymentResult = withContext(ioDispatcher) {
        val normalized = request.copy(amount = request.amount.normalized())
        notifyListeners(PaymentResult(normalized.id, PaymentStatus.PROCESSING, message = "Processing started"))
        val result = when (normalized.methodType) {
            PaymentMethodType.IN_APP_PURCHASE -> inAppGateway.process(normalized)
            PaymentMethodType.WALLET -> walletGateway.process(normalized)
        }
        notifyListeners(result)
        result
    }

    suspend fun verifyTransaction(transactionId: String, methodType: PaymentMethodType): Boolean = withContext(ioDispatcher) {
        when (methodType) {
            PaymentMethodType.IN_APP_PURCHASE -> inAppGateway.verifyTransaction(transactionId)
            PaymentMethodType.WALLET -> walletGateway.verifyTransaction(transactionId)
        }
    }

    fun authorizeWallet(walletAccountId: String, authToken: String) {
        walletGateway.authorizeWallet(walletAccountId, authToken)
    }

    fun revokeWallet(walletAccountId: String) {
        walletGateway.revokeWallet(walletAccountId)
    }

    private fun notifyListeners(result: PaymentResult) {
        listeners.forEach { listener ->
            listener.onPaymentUpdated(result)
        }
    }
}

object PaymentSecurity {
    fun maskCardLikeValue(value: String): String {
        if (value.length <= 4) return "****"
        return "*".repeat(value.length - 4) + value.takeLast(4)
    }

    fun isDeviceCompatible(context: Context): Boolean {
        return Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP ||
            ContextCompat.checkSelfPermission(context, android.Manifest.permission.INTERNET) == PackageManager.PERMISSION_GRANTED
    }

    fun ensureInternetPermission(activity: Activity, requestCode: Int = 1001) {
        val permission = android.Manifest.permission.INTERNET
        if (ActivityCompat.checkSelfPermission(activity, permission) != PackageManager.PERMISSION_GRANTED) {
            ActivityCompat.requestPermissions(activity, arrayOf(permission), requestCode)
        }
    }
}

